# app/api/holland.py
from flask import Blueprint, request, jsonify
from app.services.holland_service import HollandTestService

# 创建蓝图
holland_bp = Blueprint('holland', __name__, url_prefix='/api/holland')

# 初始化服务
holland_service = HollandTestService()


@holland_bp.route('/questions', methods=['GET'])
def get_questions():
    """
    获取所有测试题目
    返回：题目列表
    """
    try:
        questions = holland_service.load_questions()
        return jsonify({
            "code": 200,
            "message": "获取成功",
            "data": {
                "total": len(questions),
                "questions": questions
            }
        })
    except Exception as e:
        return jsonify({
            "code": 500,
            "message": f"加载题目失败: {str(e)}"
        }), 500


@holland_bp.route('/submit', methods=['POST'])
def submit_test():
    """
    提交测试答案
    请求体: {"answers": [0,1,0,1,...]} 长度为90
    """
    try:
        data = request.get_json()

        if not data:
            return jsonify({
                "code": 400,
                "message": "请提供答案数据"
            }), 400

        answers = data.get('answers')

        if not answers:
            return jsonify({
                "code": 400,
                "message": "缺少 answers 字段"
            }), 400

        # 验证答案长度
        if len(answers) != 90:
            return jsonify({
                "code": 400,
                "message": f"答案数量必须是90个，当前为 {len(answers)} 个"
            }), 400

        # 验证答案格式
        if not all(ans in [0, 1] for ans in answers):
            return jsonify({
                "code": 400,
                "message": "答案只能是0或1"
            }), 400

        # 处理测试
        result = holland_service.process_test(answers)

        return jsonify({
            "code": 200,
            "message": "测试完成",
            "data": result
        })

    except Exception as e:
        return jsonify({
            "code": 500,
            "message": f"处理失败: {str(e)}"
        }), 500


@holland_bp.route('/result-details/<type_name>', methods=['GET'])
def get_result_detail(type_name):
    """
    获取特定类型的详细描述
    """
    try:
        result_details = holland_service.load_result_descriptions()

        if type_name not in result_details:
            return jsonify({
                "code": 404,
                "message": f"未找到类型: {type_name}"
            }), 404

        return jsonify({
            "code": 200,
            "message": "获取成功",
            "data": {
                "type": type_name,
                "description": result_details[type_name]
            }
        })

    except Exception as e:
        return jsonify({
            "code": 500,
            "message": f"获取失败: {str(e)}"
        }), 500


@holland_bp.route('/health', methods=['GET'])
def health_check():
    """健康检查"""
    return jsonify({
        "code": 200,
        "message": "霍兰德测试服务正常",
        "data": {
            "status": "running",
            "service": "holland_test"
        }
    })

from flask import Blueprint, request, jsonify
from app.utils.db import get_sys_profile_by_phone
from datetime import datetime

# 创建登录蓝图
login_bp = Blueprint('login', __name__)

@login_bp.route('/login', methods=['POST'])
def login():
    """基于 phone 的简单登录接口 (密码不加密，连接 Supabase)"""
    try:
        # 尝试获取 JSON 数据，如果 Content-Type 不是 application/json 也会尝试解析
        data = request.get_json(silent=True)

        # 如果不是 JSON 或者没有提供数据，尝试从表单获取
        if data is None:
            data = request.form

        # 如果依然没有数据，返回错误
        if not data:
            return jsonify({
                "code": 400,
                "message": "请提供手机号和密码"
            }), 400

        phone = data.get('phone')
        password = data.get('password')

        if not phone or not password:
            return jsonify({
                "code": 400,
                "message": "手机号和密码不能为空"
            }), 400

        try:
            user_info = get_sys_profile_by_phone(phone)
            if not user_info:
                return jsonify({
                    "code": 401,
                    "message": "用户不存在"
                }), 401

            # 验证密码 (明文比对)
            if user_info.get('password') == password:
                return jsonify({
                    "code": 200,
                    "message": "登录成功",
                    "data": {
                        "id": user_info.get("id"),
                        "phone": user_info.get("phone"),
                        "real_name": user_info.get("real_name"),
                        "role_code": user_info.get("role_code"),
                        "avatar_url": user_info.get("avatar_url"),
                        "token": f"mock_token_{user_info.get('id')}",
                        "login_time": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                    }
                })
            else:
                return jsonify({
                    "code": 401,
                    "message": "密码错误"
                }), 401

        except Exception as db_err:
            return jsonify({
                "code": 500,
                "message": f"数据库查询错误: {str(db_err)}"
            }), 500

    except Exception as e:
        return jsonify({
            "code": 500,
            "message": f"服务器错误: {str(e)}"
        }), 500

@login_bp.route('/health', methods=['GET'])
