import os
import pandas as pd
from pyecharts import options as opts
from pyecharts.charts import Radar
from pathlib import Path

class HollandTestService:
    """霍兰德职业性格测试服务类"""

    def __init__(self):
        self.project_root = Path(__file__).resolve().parents[2]
        self.questions_file = self.project_root / "data" / "holland" / "testQuestions.txt"
        self.result_file = self.project_root / "data" / "holland" / "result.txt"
        self._questions = None
        self._result_descriptions = None

        # 确保数据目录存在
        self._ensure_data_dir()

    def _ensure_data_dir(self):
        """确保数据目录存在"""
        data_dir = self.project_root / "data" / "holland"
        if not data_dir.exists():
            data_dir.mkdir(parents=True, exist_ok=True)

    def load_questions(self):
        """加载题目列表"""
        if self._questions is not None:
            return self._questions

        questions = []
        if not self.questions_file.exists():
            # 如果文件不存在，返回示例数据
            return self._get_sample_questions()

        with open(self.questions_file, 'r', encoding='utf-8') as file:
            for line in file:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('．')
                if len(parts) == 2:
                    questions.append({
                        'id': int(parts[0]),
                        'text': parts[1]
                    })
        self._questions = questions
        return questions

    def load_result_descriptions(self):
        """加载结果描述"""
        if self._result_descriptions is not None:
            return self._result_descriptions

        types = ['艺术型', '常规型', '企业型', '研究型', '现实型', '社会型']
        result_descriptions = {}

        if not self.result_file.exists():
            return self._get_sample_results()

        with open(self.result_file, 'r', encoding='utf-8') as file:
            lines = [line.strip() for line in file.readlines() if line.strip()]

        # 每两种描述对应一种类型
        for i, type_name in enumerate(types):
            if i * 2 + 1 < len(lines):
                result_descriptions[type_name] = [
                    lines[i * 2],
                    lines[i * 2 + 1] if i * 2 + 1 < len(lines) else ''
                ]

        self._result_descriptions = result_descriptions
        return result_descriptions

    def calculate_types(self, answers):
        """
        根据答案计算各类型得分
        answers: 长度为90的列表，1表示Yes，0表示No
        返回：各类型得分的字典
        """
        type_scores = {
            '现实型': 0,
            '研究型': 0,
            '艺术型': 0,
            '社会型': 0,
            '企业型': 0,
            '常规型': 0
        }

        # 题目类型映射：根据题号除以6的余数判断
        for i, answer in enumerate(answers, start=1):
            remainder = i % 6
            if remainder == 1:
                type_scores['现实型'] += answer
            elif remainder == 2:
                type_scores['研究型'] += answer
            elif remainder == 3:
                type_scores['艺术型'] += answer
            elif remainder == 4:
                type_scores['社会型'] += answer
            elif remainder == 5:
                type_scores['企业型'] += answer
            elif remainder == 0:
                type_scores['常规型'] += answer

        return type_scores

    def get_top_types(self, scores):
        """获取得分最高的前三类型"""
        sorted_types = sorted(scores.items(), key=lambda x: x[1], reverse=True)
        return [type_name for type_name, score in sorted_types[:3]]

    def generate_radar_chart(self, scores):
        """生成雷达图HTML"""
        types_order = ['现实型', '研究型', '艺术型', '社会型', '企业型', '常规型']
        values = [scores[t] for t in types_order]

        radar = Radar()
        radar.add_schema(
            schema=[
                opts.RadarIndicatorItem(name=name, max_=15) for name in types_order
            ]
        )
        radar.add(
            "得分统计",
            [values],
            color='red',
            areastyle_opts=opts.AreaStyleOpts(opacity=0.5, color='pink')
        )
        radar.set_global_opts(
            title_opts=opts.TitleOpts(title='霍兰德职业性格测试结果'),
            legend_opts=opts.LegendOpts(selected_mode='single')
        )

        return radar.render_embed()

    def process_test(self, answers):
        """
        处理完整的测试流程
        answers: 长度为90的列表
        返回：完整的测试结果
        """
        # 1. 计算得分
        scores = self.calculate_types(answers)

        # 2. 获取前三类型
        top_types = self.get_top_types(scores)

        # 3. 加载结果描述
        result_details = self.load_result_descriptions()

        # 4. 生成雷达图
        radar_html = self.generate_radar_chart(scores)

        return {
            "scores": scores,
            "top_types": top_types,
            "result_details": result_details,
            "radar_chart": radar_html
        }

    def _get_sample_questions(self):
        """返回示例题目（用于测试）"""
        return [
            {"id": i, "text": f"示例题目 {i}：请根据实际情况回答"} 
            for i in range(1, 91)
        ]

    def _get_sample_results(self):
        """返回示例结果描述"""
        return {
            '艺术型': ['有创造力，乐于创造新颖、与众不同的成果', '喜欢艺术性的工作，如音乐、舞蹈、唱歌'],
            '常规型': ['尊重权威和规章制度，喜欢按计划办事', '喜欢常规性的工作，如记账、秘书'],
            '企业型': ['追求权力、权威和物质财富', '喜欢推销、服务、管理等工作'],
            '研究型': ['思想家而非实干家，抽象思维能力强', '喜欢各种研究型工作'],
            '现实型': ['愿意使用工具从事操作性工作', '喜欢现实性的实在的工作'],
            '社会型': ['喜欢与人交往、不断结交新的朋友', '喜欢社会交往性工作']
        }

import json
import math
import re
from datetime import datetime

from app.utils.db import supabase_request, get_http_session, get_dify_api_key, get_dify_base_url


def _ensure_float_list(v, expected_dim: int) -> list[float]:
    if v is None:
        return [0.0] * expected_dim
    if isinstance(v, str):
        try:
            v = json.loads(v)
        except Exception:
            return [0.0] * expected_dim
    if not isinstance(v, (list, tuple)):
        return [0.0] * expected_dim
    out = []
    for x in v:
        try:
            out.append(float(x))
        except Exception:
            out.append(0.0)
        if len(out) >= expected_dim:
            break
    if len(out) < expected_dim:
        out.extend([0.0] * (expected_dim - len(out)))
    return out


def _cosine_similarity(v1: list[float], v2: list[float]) -> float:
    dot = 0.0
    n1 = 0.0
    n2 = 0.0
    for a, b in zip(v1, v2):
        dot += a * b
        n1 += a * a
        n2 += b * b
    if n1 <= 1e-18 or n2 <= 1e-18:
        return 0.0
    return dot / (math.sqrt(n1) * math.sqrt(n2))


def _parse_report_section(text: str) -> dict:
    dimensions = ["tech", "soft", "project", "edu"]
    result = {}
    for dim in dimensions:
        pattern = rf"\\[{dim}\\]\\s*[:：]\\s*(.*?)(?=\\n\\s*\\[|$)"
        match = re.search(pattern, text or "", re.S)
        content = match.group(1).strip() if match else "暂无评价"
        result[dim] = content.replace("**", "")
    return result


def _call_dify_workflow(user_id: int, inputs: dict) -> dict:
    api_key = get_dify_api_key()
    if not api_key:
        return {}
    base_url = get_dify_base_url()
    session = get_http_session()
    resp = session.post(
        f"{base_url}/workflows/run",
        headers={"Authorization": f"Bearer {api_key}"},
        json={"inputs": inputs, "response_mode": "blocking", "user": f"tester_{user_id}"},
        timeout=60,
    )
    if resp.status_code >= 400:
        raise RuntimeError(f"Dify 请求失败: HTTP {resp.status_code}")
    data = resp.json()
    if "data" not in data:
        raise RuntimeError("Dify 返回结构异常")
    return data


def run_job_match(user_id: int, job_id: int) -> dict:
    cached = supabase_request(
        "GET",
        "/rest/v1/job_match_results",
        params={
            "user_id": f"eq.{int(user_id)}",
            "job_profile_id": f"eq.{int(job_id)}",
            "select": "*",
            "order": "matched_at.desc",
            "limit": "1",
        },
    )
    if isinstance(cached, list) and cached:
        return cached[0]

    job_res = supabase_request(
        "GET",
        "/rest/v1/standard_job_profiles",
        params={"id": f"eq.{int(job_id)}", "select": "*", "limit": "1"},
    )
    stu_res = supabase_request(
        "GET",
        "/rest/v1/student_portraits",
        params={"user_id": f"eq.{int(user_id)}", "select": "*", "limit": "1"},
    )
    if not isinstance(job_res, list) or not job_res:
        raise RuntimeError("未找到岗位画像")
    if not isinstance(stu_res, list) or not stu_res:
        raise RuntimeError("未找到学生画像")
    job = job_res[0]
    student = stu_res[0]

    rpc_params = {
        "p_user_id": int(user_id),
        "p_job_name": str(job.get("job_name", "")),
        "p_job_level": str(job.get("job_level", "")),
    }
    tech_data = supabase_request("POST", "/rest/v1/rpc/match_tech_v2", json_data=rpc_params)
    soft_data = supabase_request("POST", "/rest/v1/rpc/match_soft_v2", json_data=rpc_params)
    tech_rpc = tech_data[0] if isinstance(tech_data, list) and tech_data else {"match_score": 0, "missing_skills": []}
    soft_rpc = soft_data[0] if isinstance(soft_data, list) and soft_data else {"match_score": 0, "missing_skills": []}

    dim = 1024
    v_stu = _ensure_float_list(student.get("resume_embedding"), dim)
    v_job = _ensure_float_list(job.get("embedding_vector"), dim)
    vec_sim = _cosine_similarity(v_stu, v_job)
    vector_score = round(float(vec_sim) * 100.0, 2)

    exp_res = supabase_request(
        "GET",
        "/rest/v1/student_experience_detail",
        params={"user_id": f"eq.{int(user_id)}", "select": "exp_type,title,content_raw"},
    )
    exp_text = ""
    if isinstance(exp_res, list) and exp_res:
        exp_text = "\n".join(
            [f"[{e.get('exp_type', '经历')}] {e.get('title', '未命名')}: {e.get('content_raw', '')}" for e in exp_res]
        )

    dify_inputs = {
        "job_name": str(job.get("job_name", "")),
        "job_level": str(job.get("job_level", "")),
        "min_edu_level": str(job.get("min_education_level", "不限")),
        "stu_degree": str(student.get("degree", "未知")),
        "stu_major": str(student.get("major", "未填专业")),
        "exp_text": str(exp_text) if exp_text else "暂无项目经历",
        "tech_score": str(tech_rpc.get("match_score", 0)),
        "soft_score": str(soft_rpc.get("match_score", 0)),
        "vector_score": str(vector_score),
        "missing_tech": ", ".join(tech_rpc.get("missing_skills") or []) or "无核心缺失",
        "missing_soft": ", ".join(soft_rpc.get("missing_skills") or []) or "无核心缺失",
    }

    d_res = _call_dify_workflow(int(user_id), dify_inputs)
    outputs = d_res.get("data", {}).get("outputs") or {}

    edu_score = 0.0
    project_score = 0.0
    summary_dict = {}
    gap_dict = {}
    suggest_dict = {}

    try:
        edu_raw = outputs.get("edu_score", {})
        if isinstance(edu_raw, str):
            edu_raw = json.loads(edu_raw or "{}")
        edu_score = float(edu_raw.get("edu_major_score", 0) if isinstance(edu_raw, dict) else edu_raw or 0)

        proj_raw = outputs.get("project_score", {})
        if isinstance(proj_raw, str):
            proj_raw = json.loads(proj_raw or "{}")
        project_score = float(proj_raw.get("project_score", 0) if isinstance(proj_raw, dict) else proj_raw or 0)

        report_raw = outputs.get("text", {})
        if isinstance(report_raw, str):
            report_raw = json.loads(report_raw or "{}")
        if isinstance(report_raw, dict):
            summary_dict = report_raw.get("current_level_summary", {}) or {}
            gap_dict = report_raw.get("gap_analysis", {}) or {}
            suggest_dict = report_raw.get("improvement_suggestions", {}) or {}
    except Exception:
        txt = str(outputs.get("text") or "")
        summary_dict = _parse_report_section(txt)

    w_tech = float(job.get("weight_tech", 0.4) or 0.4)
    w_proj = float(job.get("weight_project", 0.2) or 0.2)
    w_acad = float(job.get("weight_academic", 0.2) or 0.2)
    w_soft = float(job.get("weight_soft", 0.1) or 0.1)
    w_vec = float(job.get("weight_vector", 0.1) or 0.1)

    total_score = (
        float(tech_rpc.get("match_score", 0)) * w_tech
        + float(project_score) * w_proj
        + float(edu_score) * w_acad
        + float(soft_rpc.get("match_score", 0)) * w_soft
        + float(vector_score) * w_vec
    )

    final_record = {
        "user_id": int(user_id),
        "job_profile_id": int(job_id),
        "total_score": round(float(total_score), 2),
        "tech_score": float(tech_rpc.get("match_score", 0)),
        "project_score": float(project_score),
        "edu_major_score": float(edu_score),
        "soft_skill_score": float(soft_rpc.get("match_score", 0)),
        "vector_similarity": float(vec_sim),
        "current_level_summary": summary_dict,
        "gap_analysis": gap_dict,
        "improvement_suggestions": suggest_dict,
        "matched_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
    }

    inserted = supabase_request("POST", "/rest/v1/job_match_results", json_data=final_record)
    if isinstance(inserted, list) and inserted:
