def _format_jobs_for_dify(jobs: list[dict]) -> str:
    """
    将岗位列表格式化为适合 Dify 输入的文本
    """
    formatted = []
    for idx, job in enumerate(jobs, 1):
        skills = job.get("required_skills", [])
        if isinstance(skills, str):
            try:
                skills = json.loads(skills)
            except Exception:
                skills = []

        skills_text = ", ".join(skills) if isinstance(skills, list) else str(skills)

        job_text = f"""
【岗位 {idx}】
- 岗位ID: {job.get('job_id')}
- 岗位名称: {job.get('job_name')}
- 公司: {job.get('company')}
- 岗位描述: {job.get('job_desc', '暂无描述')[:200]}
- 技能要求: {skills_text}
- 来源: {job.get('job_source')}
- 向量匹配分: {job.get('match_score', 0):.2f}
"""
        formatted.append(job_text.strip())

    return "\n\n".join(formatted)


def _call_dify_recommend(user_resume: str, jobs_text: str, user_id: int) -> dict:
    """
    调用 Dify API 进行智能推荐
    从 10 个候选岗位中筛选出最推荐的 3 个
    """
    api_key = get_dify_recommend_api_key()
    if not api_key:
        return {}

    base_url = get_dify_base_url()
    session = get_http_session()

    # 设计 Dify 输入参数
    payload = {
        "inputs": {
            "user_resume": user_resume[:3000],  # 限制简历长度避免 token 超限
            "candidate_jobs": jobs_text,
            "recommendation_count": "3"
        },
        "response_mode": "blocking",
        "user": f"recommend_{user_id}"
    }

    try:
        resp = session.post(
            f"{base_url}/workflows/run",
            headers={"Authorization": f"Bearer {api_key}"},
            json=payload,
            timeout=60
        )
    except Exception as e:
        raise RuntimeError(f"Dify API 调用失败: {str(e)}")

    if resp.status_code >= 400:
        raise RuntimeError(f"Dify API 返回错误: HTTP {resp.status_code}")

    try:
        data = resp.json()
    except Exception:
        raise RuntimeError("Dify 返回数据解析失败")

    outputs = data.get("data", {}).get("outputs") or {}
    return outputs


def _parse_dify_recommendations(outputs: dict, original_jobs: list[dict]) -> list[dict]:
    """
    解析 Dify 返回的推荐结果
    支持多种可能的输出格式
    """
    # 尝试从多个可能的字段中获取推荐结果
    recommendations = None

    for key in ["recommendations", "top_jobs", "selected_jobs", "result", "text"]:
        if key in outputs:
            raw = outputs[key]

            # 如果是字符串，尝试解析为 JSON
            if isinstance(raw, str):
                try:
                    recommendations = json.loads(raw)
                    if isinstance(recommendations, list):
                        break
                except Exception:
                    # 可能是纯文本，尝试提取岗位ID
                    import re
                    job_ids = re.findall(r'岗位ID[：:]\s*(\d+)', raw)
                    if job_ids:
                        recommendations = [{"job_id": int(jid)} for jid in job_ids[:3]]
                        break

            # 如果已经是列表
            elif isinstance(raw, list):
                recommendations = raw
                break

    # 如果没有找到推荐结果，返回前3个原始岗位
    if not recommendations or not isinstance(recommendations, list):
        return original_jobs[:3]

    # 匹配推荐的岗位ID到原始岗位数据
    result = []
    for rec in recommendations[:3]:
        if isinstance(rec, dict):
            job_id = rec.get("job_id")
            # 从原始岗位列表中找到对应的完整信息
            matched_job = next((j for j in original_jobs if j.get("job_id") == job_id), None)

            if matched_job:
                # 合并 Dify 返回的推荐理由
                final_job = dict(matched_job)
                final_job["recommend_reason"] = rec.get("reason") or rec.get("recommend_reason") or "该岗位与您的背景高度匹配"
                final_job["rank"] = len(result) + 1
                result.append(final_job)

    # 如果解析失败，返回前3个原始岗位
    if not result:
        for idx, job in enumerate(original_jobs[:3], 1):
            job_copy = dict(job)
            job_copy["recommend_reason"] = "基于向量相似度匹配"
            job_copy["rank"] = idx
            result.append(job_copy)

    return result


def get_smart_job_recommendations(user_id: int) -> dict:
    """
    获取智能岗位推荐

    流程：
    1. 优先从缓存表 job_recommendations 中查询
    2. 如果缓存存在，直接返回
    3. 如果缓存不存在，执行完整推荐流程并保存到缓存表
    """
    # 1. 检查缓存（查询最新的一条推荐记录）
    cached = supabase_request(
        "GET",
        "/rest/v1/job_recommendations",
        params={
            "user_id": f"eq.{int(user_id)}",
            "select": "*",
            "order": "generated_at.desc",
            "limit": "1"
        }
    )

    # 2. 如果有缓存，直接返回
    if isinstance(cached, list) and cached:
        cache_record = cached[0]
        recommended_jobs = cache_record.get("recommended_jobs", [])

        # 如果 recommended_jobs 是字符串，解析为 JSON
        if isinstance(recommended_jobs, str):
            try:
                recommended_jobs = json.loads(recommended_jobs)
            except Exception:
                recommended_jobs = []

        # 如果缓存有效，直接返回
        if recommended_jobs:
            return {
                "user_id": user_id,
                "total_candidates": 10,
                "recommended_count": len(recommended_jobs),
                "recommendations": recommended_jobs,
                "generated_at": cache_record.get("generated_at"),
                "from_cache": True
            }

    # 3. 没有缓存，执行完整推荐流程

    # 3.1 获取用户简历
    user_resume = _get_user_resume(user_id)
    if not user_resume:
        raise RuntimeError("未找到用户简历，请先完善个人信息")

    # 3.2 调用 Supabase 函数获取候选岗位
    candidate_jobs = _call_supabase_function(user_id)

    if not candidate_jobs:
        raise RuntimeError("未找到匹配的岗位")

    # 3.3 格式化岗位信息用于 Dify 分析
    jobs_text = _format_jobs_for_dify(candidate_jobs)

    # 3.4 调用 Dify 进行智能推荐
    dify_outputs = _call_dify_recommend(user_resume, jobs_text, user_id)

    # 3.5 解析 Dify 返回结果
    top_recommendations = _parse_dify_recommendations(dify_outputs, candidate_jobs)

    # 3.6 保存到缓存表
    now = _iso_now()
    cache_data = {
        "user_id": int(user_id),
        "recommended_jobs": top_recommendations,
        "generated_at": now
    }

    try:
        supabase_request("POST", "/rest/v1/job_recommendations", json_data=cache_data)
    except Exception as e:
        # 缓存保存失败不影响返回结果
        print(f"警告：推荐结果缓存保存失败: {e}")

    # 3.7 构建返回结果
    return {
        "user_id": user_id,
        "total_candidates": len(candidate_jobs),
        "recommended_count": len(top_recommendations),
        "recommendations": top_recommendations,
        "generated_at": now,
        "from_cache": False
    }

