def _call_dify_tasks(target_job_name: str, gap: Any, suggest: Any) -> list[dict]:
    def _to_text_input(v: Any) -> str:
        if v is None:
            return ""
        if isinstance(v, str):
            return v
        try:
            return json.dumps(v, ensure_ascii=False)
        except Exception:
            return str(v)

    api_key = get_dify_task_api_key()
    if not api_key:
        return []
    base_url = get_dify_base_url()
    sess = get_http_session()
    payload = {
        "inputs": {
            "target_job_name": target_job_name,
            "gap_analysis": _to_text_input(gap),
            "improvement_suggestions": _to_text_input(suggest),
        },
        "response_mode": "blocking",
        "user": f"roadmap_{target_job_name}",
    }
    try:
        resp = sess.post(
            f"{base_url}/workflows/run",
            headers={"Authorization": f"Bearer {api_key}"},
            json=payload,
            timeout=60,
        )
    except Exception:
        return []
    if resp.status_code >= 400:
        return []
    data = {}
    try:
        data = resp.json()
    except Exception:
        return []
    outputs = data.get("data", {}).get("outputs") or {}
    raw = None
    for k in ["tasks", "todo_list", "list", "items", "text", "result"]:
        if k in outputs:
            raw = outputs.get(k)
            if raw:
                break
    if raw is None:
        raw = outputs
    def _parse_list_from_text(text: str):
        s = (text or "").strip()
        if s.startswith("```"):
            s = re.sub(r"^```[a-zA-Z]*\s*", "", s)
            s = re.sub(r"\s*```$", "", s)
        if not (s.startswith("[") and s.endswith("]")):
            m = re.search(r"\[[\s\S]*\]", s)
            s = m.group(0) if m else s
        try:
            out = json.loads(s)
            if isinstance(out, list):
                return out
        except Exception:
            pass
        try:
            out = ast.literal_eval(s)
            if isinstance(out, list):
                return out
        except Exception:
            pass
        return None

    if isinstance(raw, str):
        tasks = _parse_list_from_text(raw)
    else:
        tasks = raw
    if not isinstance(tasks, list):
        candidates = []
        if isinstance(outputs, dict):
            for v in outputs.values():
                if isinstance(v, str):
                    try:
                        val = _parse_list_from_text(v)
                        if isinstance(val, list):
                            candidates = val
                            break
                    except Exception:
                        continue
                if isinstance(v, list):
                    candidates = v
                    break
        tasks = candidates if isinstance(candidates, list) else []
    if not tasks:
        base_tasks = []
        if isinstance(suggest, dict):
            for k, v in suggest.items():
                title = str(k).strip()
                if title:
                    base_tasks.append({"task_title": title, "ai_guidance": str(v)[:500], "priority": 3})
        elif isinstance(suggest, list):
            for idx, v in enumerate(suggest):
                title = str(v).strip()
                if title:
                    base_tasks.append({"task_title": title, "ai_guidance": "", "priority": 3})
        if not base_tasks and isinstance(gap, dict):
            for k in gap.keys():
                title = str(k).strip()
                if title:
                    base_tasks.append({"task_title": title, "ai_guidance": "优先补齐该能力差距", "priority": 3})
        tasks = base_tasks
    if not isinstance(tasks, list):
        tasks = []
    norm = []
    for item in tasks:
        if not isinstance(item, dict):
            continue
        title = str(item.get("task_title") or "").strip()
        if not title:
            continue
        prio = item.get("priority")
        try:
            prio = int(prio) if prio is not None else 3
        except Exception:
            prio = 3
        norm.append(
            {
                "task_title": title,
                "priority": prio,
                "ai_guidance": str(item.get("ai_guidance") or "").strip(),
            }
        )
    return norm


