        payload.append(
            {
                "roadmap_id": int(roadmap_id),
                "task_title": t.get("task_title"),
                "task_type": t.get("task_type") or "",
                "is_completed": False,
                "ai_guidance": t.get("ai_guidance") or "",
                "priority": int(t.get("priority") or 3),
                "created_at": now,
            }
        )
    inserted = supabase_request("POST", "/rest/v1/user_roadmap_tasks", json_data=payload)
    if isinstance(inserted, list):
        return inserted
    return []


def create_roadmap(user_id: int, target_job_id: int, roadmap_vision: str | None = None) -> dict:
    exists = supabase_request(
        "GET",
        "/rest/v1/user_roadmaps",
        params={
            "user_id": f"eq.{int(user_id)}",
            "target_job_id": f"eq.{int(target_job_id)}",
            "select": "*",
            "limit": "1",
        },
    )
    if isinstance(exists, list) and exists:
        roadmap = exists[0]
        existed_tasks = _get_roadmap_tasks(int(roadmap.get("id") or 0))
        if existed_tasks:
            return {"existed": True, "roadmap": roadmap, "tasks": existed_tasks}
        match = _get_or_create_match(user_id, target_job_id)
        gap = match.get("gap_analysis") or {}
        suggest = match.get("improvement_suggestions") or {}
        job = _get_job(target_job_id)
        name = job.get("job_name") if job else (roadmap.get("target_job_name") or str(target_job_id))
        tasks_parsed = _call_dify_tasks(name, gap, suggest)
        tasks_inserted = _insert_tasks(int(roadmap.get("id") or 0), tasks_parsed)
        return {"existed": True, "roadmap": roadmap, "tasks": tasks_inserted}
    job = _get_job(target_job_id)
    name = job.get("job_name") if job else ""
    now = _iso_now()
    payload = {
        "user_id": int(user_id),
        "target_job_id": int(target_job_id),
        "target_job_name": name,
        "roadmap_vision": roadmap_vision or "",
        "is_active": True,
        "created_at": now,
    }
    created = supabase_request("POST", "/rest/v1/user_roadmaps", json_data=payload)
    roadmap = created[0] if isinstance(created, list) and created else payload
    match = _get_or_create_match(user_id, target_job_id)
    gap = match.get("gap_analysis") or {}
    suggest = match.get("improvement_suggestions") or {}
    tasks_parsed = _call_dify_tasks(name or str(target_job_id), gap, suggest)
    tasks_inserted = _insert_tasks(int(roadmap.get("id") or 0), tasks_parsed)
    return {"existed": False, "roadmap": roadmap, "tasks": tasks_inserted}

