def _get_session():
    global _session
    if _session is not None:
        return _session
    global requests, HTTPAdapter
    if requests is None or HTTPAdapter is None:
        try:
            import requests as _requests
            from requests.adapters import HTTPAdapter as _HTTPAdapter
            from requests.exceptions import RequestException as _RequestException, SSLError as _SSLError
        except Exception:
            raise RuntimeError("缺少 requests 依赖")
        requests = _requests
        HTTPAdapter = _HTTPAdapter
        globals()["RequestException"] = _RequestException
        globals()["SSLError"] = _SSLError
    s = requests.Session()
    s.trust_env = False
    s.headers.update({"Accept": "application/json"})
    adapter = HTTPAdapter(pool_connections=16, pool_maxsize=16, max_retries=0)
    s.mount("https://", adapter)
    s.mount("http://", adapter)
    _session = s
    return _session


def _load_knowledge_key() -> str | None:
    _load_env()
    project_root = Path(__file__).resolve().parents[2]
