def supabase_request(method: str, endpoint: str, params: dict = None, json_data: dict = None) -> list | dict | None:
    """
    通用 Supabase REST 请求封装
    :param method: GET, POST, PATCH, DELETE
    :param endpoint: 比如 '/rest/v1/sys_profiles'
    :param params: URL 查询参数字典
    :param json_data: POST/PATCH 的 body 数据
    :return: 解析后的 JSON 数据
    """
    supabase_url = get_supabase_url()
    supabase_key = get_supabase_key()
    if not supabase_url or not supabase_key:
        raise RuntimeError("Supabase 配置缺失")

    url = f"{supabase_url.rstrip('/')}/{endpoint.lstrip('/')}"

    headers = {
        "apikey": supabase_key,
        "Authorization": f"Bearer {supabase_key}",
        "Accept": "application/json",
    }


    if method.upper() in ("POST", "PATCH", "DELETE"):
        headers["Prefer"] = "return=representation"

    try:
        verify = True
        if certifi is not None:
            try:
                verify = certifi.where()
            except Exception:
                verify = True

        s = _get_session()
        # 对于 RPC 调用（特别是向量查询），使用更长的超时时间
        timeout_val = 30 if endpoint.startswith("/rest/v1/rpc/") else 10

        resp = s.request(
            method=method.upper(),
            url=url,
            headers=headers,
            params=params,
            json=json_data,
            timeout=timeout_val,
            verify=verify,
        )

        if resp.status_code >= 400:
            raise RuntimeError(f"Supabase 请求失败: HTTP {resp.status_code} - {resp.text}")

        raw = resp.text
    except SSLError as e:
        raise RuntimeError(f"Supabase 网络连接失败 (SSL): {str(e)}") from e
    except RequestException as e:
        raise RuntimeError(f"Supabase 网络连接失败: {str(e)}") from e
    except Exception as e:
        raise RuntimeError(f"Supabase 请求异常: {str(e)}") from e

    if not raw:
        return None

    try:
        data = json.loads(raw)
        return data
    except Exception as e:
        raise RuntimeError("Supabase 返回数据解析失败") from e


def get_sys_profile_by_phone(phone: str) -> dict | None:
    safe_phone = quote(phone, safe="")

    # 直接使用封装好的 supabase_request
    data = supabase_request(
        method="GET",
        endpoint="/rest/v1/sys_profiles",
        params={
            "select": "id,role_code,password,phone,real_name,avatar_url,resume_url",
            "phone": f"eq.{safe_phone}",
            "limit": "1"
        }
    )

    if isinstance(data, list) and data:
        return data[0]
    return None
